selector_to_html = {"a[href=\"#execution-modes\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">execution modes<a class=\"headerlink\" href=\"#execution-modes\" title=\"Link to this heading\">#</a></h2><p>the gui provides two modes, toggled by \u201cRun in background\u201d checkbox.</p>", "a[href=\"#key-files\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">key files<a class=\"headerlink\" href=\"#key-files\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#mode-b-in-gui-daemon-threads\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">mode B: in-gui daemon threads<a class=\"headerlink\" href=\"#mode-b-in-gui-daemon-threads\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#multi-core-parallel-processing\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">multi-core parallel processing<a class=\"headerlink\" href=\"#multi-core-parallel-processing\" title=\"Link to this heading\">#</a></h1><p>architecture notes for suite2p parallel plane processing via the gui RUN tab.</p>", "a[href=\"#no-cancellation-for-in-gui-mode\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">no cancellation for in-gui mode<a class=\"headerlink\" href=\"#no-cancellation-for-in-gui-mode\" title=\"Link to this heading\">#</a></h3><p>background subprocess has kill support via ProcessManager, but the in-gui ThreadPoolExecutor\nhas no cancel button. <code class=\"docutils literal notranslate\"><span class=\"pre\">self._active_executor</span></code> is stored but never used for on-demand shutdown.\n<code class=\"docutils literal notranslate\"><span class=\"pre\">executor.shutdown(wait=False,</span> <span class=\"pre\">cancel_futures=True)</span></code> (python 3.9+) would enable this.</p>", "a[href=\"#mode-a-background-subprocess-default\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">mode A: background subprocess (default)<a class=\"headerlink\" href=\"#mode-a-background-subprocess-default\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#threadpoolexecutor-vs-processpoolexecutor\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">ThreadPoolExecutor vs ProcessPoolExecutor<a class=\"headerlink\" href=\"#threadpoolexecutor-vs-processpoolexecutor\" title=\"Link to this heading\">#</a></h3><p>suite2p is cpu-heavy. python\u2019s GIL means threads can\u2019t achieve true cpu parallelism for\npython-bound work. numpy/C extensions release the GIL so threads do help for the heavy\ncompute, but binary extraction and python orchestration serialize. ProcessPoolExecutor\nwould give true parallelism but requires picklable arguments (arr and logger are not).</p>", "a[href=\"#log-directory-path-mismatch\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/mbo_utilities/issues/160\">#160</a> - log directory path mismatch<a class=\"headerlink\" href=\"#log-directory-path-mismatch\" title=\"Link to this heading\">#</a></h3><p>sidecar writers use <code class=\"docutils literal notranslate\"><span class=\"pre\">~/mbo/logs/</span></code>, but <code class=\"docutils literal notranslate\"><span class=\"pre\">spawn()</span></code> creates log files in <code class=\"docutils literal notranslate\"><span class=\"pre\">~/.mbo/logs/</span></code>.\nworks by accident since they\u2019re tracked independently, but fragile.</p>", "a[href=\"#parallel-checkbox-hidden-for-5d-data\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/mbo_utilities/issues/159\">#159</a> - parallel checkbox hidden for 5D data<a class=\"headerlink\" href=\"#parallel-checkbox-hidden-for-5d-data\" title=\"Link to this heading\">#</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">settings.py:688</span></code> only checks <code class=\"docutils literal notranslate\"><span class=\"pre\">data.ndim</span> <span class=\"pre\">==</span> <span class=\"pre\">4</span></code> for num_planes detection. 5D TCZYX data\n(<code class=\"docutils literal notranslate\"><span class=\"pre\">ndim</span> <span class=\"pre\">==</span> <span class=\"pre\">5</span></code>) falls through, <code class=\"docutils literal notranslate\"><span class=\"pre\">num_planes</span></code> stays 1, and the parallel checkbox never appears.</p>", "a[href=\"#file-handle-leak-double-save\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/mbo_utilities/issues/161\">#161</a> - file handle leak + double <code class=\"docutils literal notranslate\"><span class=\"pre\">_save()</span></code><a class=\"headerlink\" href=\"#file-handle-leak-double-save\" title=\"Link to this heading\">#</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">spawn()</span></code> opens <code class=\"docutils literal notranslate\"><span class=\"pre\">f_out</span></code> for log redirection but never closes it in the parent process.\nalso calls <code class=\"docutils literal notranslate\"><span class=\"pre\">self._save()</span></code> twice in a row.</p>", "a[href=\"#no-per-plane-parallelism-in-background-mode\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">no per-plane parallelism in background mode<a class=\"headerlink\" href=\"#no-per-plane-parallelism-in-background-mode\" title=\"Link to this heading\">#</a></h3><p>background subprocess mode (the default) processes planes sequentially via <code class=\"docutils literal notranslate\"><span class=\"pre\">pipeline()</span></code>.\nusers who enable \u201cparallel\u201d but leave \u201crun in background\u201d checked get no parallelism.\nthe parallel checkbox only applies to daemon-thread mode. consider either disabling\nthe checkbox when background mode is on, or passing parallelism settings to the worker.</p>", "a[href=\"#worker-function\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">worker function<a class=\"headerlink\" href=\"#worker-function\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">_run_plane_worker_thread(config)</span></code> at <code class=\"docutils literal notranslate\"><span class=\"pre\">settings.py:2014</span></code> is a pure function taking a snapshot dict.\nall gui state is pre-extracted into the config before thread launch to avoid data races.\neach worker: writes binary data via <code class=\"docutils literal notranslate\"><span class=\"pre\">imwrite(.bin)</span></code> -&gt; calls <code class=\"docutils literal notranslate\"><span class=\"pre\">lbm_suite2p_python.run_plane()</span></code>.</p>", "a[href=\"#executor-shutdown-wait-false-in-finally-block\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">executor.shutdown(wait=False) in finally block<a class=\"headerlink\" href=\"#executor-shutdown-wait-false-in-finally-block\" title=\"Link to this heading\">#</a></h3><p>at <code class=\"docutils literal notranslate\"><span class=\"pre\">settings.py:1987</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">shutdown(wait=False)</span></code> is called after <code class=\"docutils literal notranslate\"><span class=\"pre\">as_completed()</span></code>. in the\nhappy path all futures are done. but if an exception interrupts the <code class=\"docutils literal notranslate\"><span class=\"pre\">as_completed()</span></code> loop,\nsome futures may still be running. <code class=\"docutils literal notranslate\"><span class=\"pre\">wait=True</span></code> would be safer since we\u2019re already in a\ndaemon thread.</p>", "a[href=\"#lbm-suite2p-python-80-is-volumetric-unboundlocalerror\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-Suite2p-Python/issues/80\">lbm-suite2p-python#80</a> - <code class=\"docutils literal notranslate\"><span class=\"pre\">is_volumetric</span></code> UnboundLocalError<a class=\"headerlink\" href=\"#lbm-suite2p-python-80-is-volumetric-unboundlocalerror\" title=\"Link to this heading\">#</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">pipeline()</span></code> in <code class=\"docutils literal notranslate\"><span class=\"pre\">run_lsp.py:289</span></code> crashes because <code class=\"docutils literal notranslate\"><span class=\"pre\">is_volumetric</span></code> is only assigned inside\n<code class=\"docutils literal notranslate\"><span class=\"pre\">if</span> <span class=\"pre\">roi_mode</span> <span class=\"pre\">is</span> <span class=\"pre\">not</span> <span class=\"pre\">None</span> <span class=\"pre\">and</span> <span class=\"pre\">supports_roi(arr):</span></code>. the normal path (<code class=\"docutils literal notranslate\"><span class=\"pre\">roi_mode=None</span></code>) skips\nthe block entirely, leaving the variable unbound.</p><p>error log from a real run (pid=25612, 10 tiff files, planes=[1,3,5]):</p>", "a[href=\"#potential-improvements\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">potential improvements<a class=\"headerlink\" href=\"#potential-improvements\" title=\"Link to this heading\">#</a></h2><h3>no per-plane parallelism in background mode<a class=\"headerlink\" href=\"#no-per-plane-parallelism-in-background-mode\" title=\"Link to this heading\">#</a></h3><p>background subprocess mode (the default) processes planes sequentially via <code class=\"docutils literal notranslate\"><span class=\"pre\">pipeline()</span></code>.\nusers who enable \u201cparallel\u201d but leave \u201crun in background\u201d checked get no parallelism.\nthe parallel checkbox only applies to daemon-thread mode. consider either disabling\nthe checkbox when background mode is on, or passing parallelism settings to the worker.</p>", "a[href=\"#shared-arr-metadata-mutated-across-threads\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\"><a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/mbo_utilities/issues/158\">#158</a> - shared <code class=\"docutils literal notranslate\"><span class=\"pre\">arr.metadata</span></code> mutated across threads<a class=\"headerlink\" href=\"#shared-arr-metadata-mutated-across-threads\" title=\"Link to this heading\">#</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">_run_plane_worker_thread()</span></code> at <code class=\"docutils literal notranslate\"><span class=\"pre\">settings.py:2089-2094</span></code> calls <code class=\"docutils literal notranslate\"><span class=\"pre\">arr.metadata.pop()</span></code> on the\noriginal shared array object. all parallel threads share the same <code class=\"docutils literal notranslate\"><span class=\"pre\">arr</span></code>, creating a dict\nmutation race. the local <code class=\"docutils literal notranslate\"><span class=\"pre\">lazy_mdata</span></code> copy is correct but the original shouldn\u2019t be touched.</p>", "a[href=\"#data-flow\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">data flow<a class=\"headerlink\" href=\"#data-flow\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#open-bugs\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">open bugs<a class=\"headerlink\" href=\"#open-bugs\" title=\"Link to this heading\">#</a></h2><h3><a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-Suite2p-Python/issues/80\">lbm-suite2p-python#80</a> - <code class=\"docutils literal notranslate\"><span class=\"pre\">is_volumetric</span></code> UnboundLocalError<a class=\"headerlink\" href=\"#lbm-suite2p-python-80-is-volumetric-unboundlocalerror\" title=\"Link to this heading\">#</a></h3><p><code class=\"docutils literal notranslate\"><span class=\"pre\">pipeline()</span></code> in <code class=\"docutils literal notranslate\"><span class=\"pre\">run_lsp.py:289</span></code> crashes because <code class=\"docutils literal notranslate\"><span class=\"pre\">is_volumetric</span></code> is only assigned inside\n<code class=\"docutils literal notranslate\"><span class=\"pre\">if</span> <span class=\"pre\">roi_mode</span> <span class=\"pre\">is</span> <span class=\"pre\">not</span> <span class=\"pre\">None</span> <span class=\"pre\">and</span> <span class=\"pre\">supports_roi(arr):</span></code>. the normal path (<code class=\"docutils literal notranslate\"><span class=\"pre\">roi_mode=None</span></code>) skips\nthe block entirely, leaving the variable unbound.</p><p>error log from a real run (pid=25612, 10 tiff files, planes=[1,3,5]):</p>", "a[href=\"#no-progress-reporting-for-in-gui-parallel-mode\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">no progress reporting for in-gui parallel mode<a class=\"headerlink\" href=\"#no-progress-reporting-for-in-gui-parallel-mode\" title=\"Link to this heading\">#</a></h3><p>background mode reports granular progress through sidecar files. in-gui parallel mode only\nlogs completion messages with no progress bar or per-plane status visible during execution.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
